Here are the public test cases for feature12_cross_origin_embedder_policy:
{
  "description": "The Cross-Origin-Embedder-Policy header may only be emitted alongside an enabled Cross-Origin-Resource-Policy. With the resource policy present both headers are emitted; requesting the embedder policy alone is rejected as an invalid configuration; the header is absent when not enabled.",
  "cases": [
    {
      "input": {
        "headers": {
          "cross_origin_resource_policy": {},
          "cross_origin_embedder_policy": {}
        }
      },
      "expected_output": "Cross-Origin-Embedder-Policy: require-corp\nCross-Origin-Resource-Policy: same-origin\n"
    },
    {
      "input": {
        "headers": {
          "cross_origin_embedder_policy": {}
        }
      },
      "expected_output": "error=embedder_policy_requires_resource_policy\n"
    }
  ]
}

Here are the public test cases for feature13_content_security_policy:
{
  "description": "The Content-Security-Policy family: a plain enabled policy emits the block/upgrade directives; a sandbox prepends a sandbox directive; legacy-compatibility mode mirrors the policy into the X-Content-Security-Policy header; report-only mode emits a separate report-only header carrying a report-uri; and no header is emitted when the policy is not enabled.",
  "cases": [
    {
      "input": {
        "headers": {
          "content_security_policy": {
            "sandbox": [
              "allow-forms",
              "allow-scripts",
              "allow-same-origin"
            ]
          }
        }
      },
      "expected_output": "Content-Security-Policy: sandbox allow-forms allow-scripts allow-same-origin;block-all-mixed-content;upgrade-insecure-requests;\n"
    },
    {
      "input": {
        "headers": {
          "content_security_policy": {
            "report_only": true,
            "report_uri": "https://localhost:5001/report-uri"
          }
        }
      },
      "expected_output": "Content-Security-Policy-Report-Only: block-all-mixed-content;upgrade-insecure-requests;report-uri https://localhost:5001/report-uri;\n"
    }
  ]
}

Here are the public test cases for feature14_csp_directive_formatting:
{
  "description": "Content-Security-Policy directive formatting rules: keyword tokens are wrapped in single quotes, URI tokens are left unquoted, exactly one space separates tokens (no leading, trailing or double spaces), each source list ends with a single semicolon, and a repeated URI is not duplicated.",
  "cases": [
    {
      "input": {
        "headers": {
          "content_security_policy": {
            "block_all_mixed_content": false,
            "upgrade_insecure_requests": false,
            "directives": {
              "script-src": [
                {
                  "keyword": "self"
                },
                {
                  "keyword": "unsafe-inline"
                },
                {
                  "keyword": "none"
                }
              ]
            }
          }
        }
      },
      "expected_output": "Content-Security-Policy: script-src 'self' 'unsafe-inline' 'none';\n"
    },
    {
      "input": {
        "headers": {
          "content_security_policy": {
            "block_all_mixed_content": false,
            "upgrade_insecure_requests": false,
            "directives": {
              "img-src": [
                {
                  "keyword": "self"
                },
                {
                  "uri": "data:"
                },
                {
                  "uri": "https://cdn.abc.net"
                },
                {
                  "uri": "https://cdn.abc.org"
                }
              ]
            }
          }
        }
      },
      "expected_output": "Content-Security-Policy: img-src 'self' data: https://cdn.abc.net https://cdn.abc.org;\n"
    }
  ]
}

Here are the public test cases for feature15_clear_site_data_global:
{
  "description": "When Clear-Site-Data is enabled for all responses the header lists each requested data type as a quoted token; a wildcard collapses the whole value to \"*\" and takes precedence over any other token; duplicate tokens are removed; and the header is absent when not enabled.",
  "cases": [
    {
      "input": {
        "headers": {
          "clear_site_data": {}
        }
      },
      "expected_output": "Clear-Site-Data: \"cache\",\"cookies\",\"storage\"\n"
    },
    {
      "input": {
        "headers": {
          "clear_site_data": {
            "directives": [
              "cache",
              "*",
              "cookies"
            ]
          }
        }
      },
      "expected_output": "Clear-Site-Data: \"*\"\n"
    },
    {
      "input": {
        "headers": {}
      },
      "expected_output": "<no-headers>\n"
    }
  ]
}

Here are the public test cases for feature16_clear_site_data_paths:
{
  "description": "Path-scoped Clear-Site-Data emits the header only for requests whose path matches a configured entry; when several configured paths are prefixes of the request the most specific (longest) match wins; and configuring an entry with an empty path or an empty token list is rejected as an invalid configuration.",
  "cases": [
    {
      "input": {
        "request_path": "/logout",
        "headers": {
          "clear_site_data_paths": {
            "paths": {
              "/logout": [
                "*"
              ]
            }
          }
        }
      },
      "expected_output": "Clear-Site-Data: \"*\"\n"
    },
    {
      "input": {
        "request_path": "/account/logout",
        "headers": {
          "clear_site_data_paths": {
            "paths": {
              "/account": [
                "cache"
              ],
              "/account/logout": [
                "*"
              ]
            }
          }
        }
      },
      "expected_output": "Clear-Site-Data: \"*\"\n"
    },
    {
      "input": {
        "headers": {
          "clear_site_data_add_paths": [
            {
              "path": "",
              "directives": [
                "cache"
              ]
            }
          ]
        }
      },
      "expected_output": "error=missing_required_value\nfield=path\n"
    }
  ]
}

