Here are the public test cases for feature8_cache_control:
{
  "description": "The Cache-Control header value is produced by a strict precedence among the requested directives: no-cache wins over private, which wins over must-revalidate, which wins over the max-age/no-store pair.",
  "cases": [
    {
      "input": {
        "headers": {
          "cache_control": {}
        }
      },
      "expected_output": "Cache-Control: max-age=0,no-store\n"
    },
    {
      "input": {
        "headers": {
          "cache_control": {
            "private": true
          }
        }
      },
      "expected_output": "Cache-Control: private\n"
    },
    {
      "input": {
        "headers": {
          "cache_control": {
            "no_cache": true,
            "no_store": false
          }
        }
      },
      "expected_output": "Cache-Control: no-cache\n"
    }
  ]
}

